// Unwrap the webhook body so downstream nodes can read the Discord
// payload fields at the top level — matches the shape the Channel Router
// was originally written against.
const item = $input.item.json || {};
const body = item.body || item;
return [{ json: body }];

// Channel Router
//
// Reads the incoming Discord message (forwarded by the discord-relay
// container), looks up routing for the channel, and decides whether Bruce
// should respond. Also loads the appropriate persona content to be used
// as the Claude system prompt.
//
// Keep the `ROUTING` and `PERSONAS` tables in sync with:
//   config/channel-routing.json
//   prompts/channel-personas/*.md
//
// When you change a persona, edit the string literal below AND the .md
// file in the repo, then re-save this workflow.

const ROUTING = {
  'general':        { behavior: 'mention-only', persona: 'general' },
  'family':         { behavior: 'mention-only', persona: 'family' },
  'announcements':  { behavior: 'read-only',    persona: null },
  'fig':            { behavior: 'always',       persona: 'fig' },
  'jake-personal':  { behavior: 'always',       persona: 'jake-personal' },
  'lake':           { behavior: 'mention-only', persona: 'lake' },
  'cps':            { behavior: 'mention-only', persona: 'cps' },
  'loubi-personal': { behavior: 'always',       persona: 'loubi-personal' },
  'wis':            { behavior: 'always',       persona: 'wis' },
  'joce-personal':  { behavior: 'always',       persona: 'joce-personal' },
  'joce-school':    { behavior: 'always',       persona: 'joce-school' },
  'nana-personal':  { behavior: 'always',       persona: 'nana-personal' },
};

// Short stub personas — REPLACE THESE with the real prompt text from
// prompts/channel-personas/<slug>.md. Kept short here so the workflow JSON
// stays under the 1 MB import ceiling. For production, paste the full
// persona markdown between the backticks for each slug.
const PERSONAS = {
  'general':        `You are Bruce in #general. See prompts/channel-personas/general.md for the full persona; paste it here.`,
  'family':         `You are Bruce in #family. See prompts/channel-personas/family.md for the full persona; paste it here.`,
  'fig':            `You are Bruce in #fig. See prompts/channel-personas/fig.md for the full persona; paste it here.`,
  'jake-personal':  `You are Bruce in #jake-personal. See prompts/channel-personas/jake-personal.md for the full persona; paste it here.`,
  'lake':           `You are Bruce in #lake. See prompts/channel-personas/lake.md for the full persona; paste it here.`,
  'cps':            `You are Bruce in #cps. See prompts/channel-personas/cps.md for the full persona; paste it here.`,
  'loubi-personal': `You are Bruce in #loubi-personal. See prompts/channel-personas/loubi-personal.md for the full persona; paste it here.`,
  'wis':            `You are Bruce in #wis. See prompts/channel-personas/wis.md for the full persona; paste it here.`,
  'joce-personal':  `You are Bruce in #joce-personal. See prompts/channel-personas/joce-personal.md for the full persona; paste it here.`,
  'joce-school':    `You are Bruce in #joce-school. See prompts/channel-personas/joce-school.md for the full persona; paste it here.`,
  'nana-personal':  `You are Bruce in #nana-personal. See prompts/channel-personas/nana-personal.md for the full persona; paste it here.`,
};

const msg = $input.item.json;

// Normalize the shape of the Discord payload across n8n versions.
const channelName = msg.channel_name || (msg.channel && msg.channel.name) || '';
const channelId   = msg.channel_id   || (msg.channel && msg.channel.id)   || '';
const messageId   = msg.id           || msg.message_id                     || '';
const userId      = (msg.author && msg.author.id) || msg.author_id || '';
const content     = msg.content || '';
const mentions    = (msg.mentions || []).map(m => m.id || m);
const botMentioned = mentions.includes($env.DISCORD_BOT_USER_ID);
const isReplyToBot =
  msg.referenced_message &&
  msg.referenced_message.author &&
  msg.referenced_message.author.id === $env.DISCORD_BOT_USER_ID;

const route = ROUTING[channelName] || { behavior: 'read-only', persona: null };

let shouldRespond = false;
if (route.behavior === 'always')        shouldRespond = true;
if (route.behavior === 'mention-only')  shouldRespond = botMentioned || isReplyToBot;
if (route.behavior === 'read-only')     shouldRespond = false;

return [{
  json: {
    shouldRespond,
    channelId,
    channelName,
    messageId,
    userId,
    content,
    behavior: route.behavior,
    persona: route.persona,
    systemPrompt: route.persona ? (PERSONAS[route.persona] || '') : '',
  }
}];

// Build the Anthropic /v1/messages request body.
//
// Conversation history came back newest-first from Postgres; reverse it
// before feeding to Claude, which expects oldest-first.

const router   = $('Channel Router').first().json;
const rows     = $input.all().map(i => i.json).reverse();

const messages = rows
  .filter(r => r.role === 'user' || r.role === 'assistant')
  .map(r => ({ role: r.role, content: r.content }));

messages.push({ role: 'user', content: router.content });

return [{
  json: {
    ...router,
    requestBody: {
      model: $env.ANTHROPIC_MODEL || 'claude-sonnet-4-6',
      max_tokens: 1024,
      system: router.systemPrompt,
      messages,
    },
  }
}];

// Extract Claude's reply text and prep the fields needed downstream.
const router = $('Channel Router').first().json;
const apiRes = $input.item.json;

const reply = (apiRes.content || [])
  .filter(c => c.type === 'text')
  .map(c => c.text)
  .join('\n\n')
  .trim();

if (!reply) {
  throw new Error('Empty reply from Claude — check response shape: ' + JSON.stringify(apiRes).slice(0, 500));
}

return [{
  json: {
    ...router,
    reply,
    // Discord caps message length at 2000 chars; truncate safely.
    replyTruncated: reply.length > 1950 ? reply.slice(0, 1950) + '…' : reply,
  }
}];
